INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989403","title":"Перчатка Бесконечности","author":"Рон Лим,Джордж Перес,Джим Старлин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002850698/140/fc31/__Perchatka_Beskonechnosti.jpg","isbn":"978-5-640823-8-6","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Перчатка Бесконечности была святым Граалем для тёмного титана Таноса - величайшим призом, которым он жаждал обладать.  С перчаткой Бесконечности Танос стал всемогущ. у него появился абсолютный контроль над всеми аспектами времени, пространства, силы, реальности, разума и души. Тёмные времена для всей вселенной наступили из-за этой новообретённой мощи. Герои Земли под предводительством загадочного Адама Варлока тщетно пытаются помещать богоподобному нигилисту и предотвратить безумное погружение галактики в забвение. А если падут герои, то в дело вмешаются сами астральные божества вселенной. Но кто сможет  победить в этой ужасной схватке? Кто сможет выжить?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4.5,"review":"","added":9999363,"hdCover":""},{"id":"0989402","title":"Injustice: Gods Among Us: Year Five, Vol. 3","author":"Брайан Буччеллато","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003548170/140/ab8a/Brajan_Buchchellato__Injustice_Gods_Among_Us_Year_Five_Vol._3.jpg","isbn":"1401272460","publisher":"DC Comics","pubDate":"2017","language":"","series":"Injustice","genres":[],"annotation":"This is it! The final year and final volume of INJUSTICE: GODS AMONG US, leading into the storyline of the hit video game! Earths collide as Batman and his team of heroes work to stop a rampaging Superman and his deadly allies. In this, the final battle of the best-selling digital-first series, allegiances are tested, lives are won and lost, and heroes old and new face off in one of the most intense and epic clashes any corner of the DC Universe has ever seen. The finale is here, as writer Brian Buccellato (THE FLASH) unveils the final chapter before the events of the hit video game phenomenon in INJUSTICE: GODS AMONG US YEAR FIVE VOL. 3. Collects issues #13-20.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4,"review":"","added":9999362,"hdCover":""},{"id":"0989401","title":"Injustice: Gods Among Us: Year Five, Vol. 2","author":"Брайан Буччеллато","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003548166/140/6897/Brajan_Buchchellato__Injustice_Gods_Among_Us_Year_Five_Vol._2.jpg","isbn":"1401268846","publisher":"DC Comics","pubDate":"2017","language":"","series":"Injustice","genres":[],"annotation":"This is it: the final year and final volume of INJUSTICE: GODS AMONG US, leading into the storyline of the hit video game! Having defeated the Green Lantern Corps, the forces of magic, and now the gods themselves, Superman''s totalitarian regime seems to have eliminated all threats. Yet uneasy lies the crown on the head of the Man of Steel. Still obsessed with the outlaw Batman and worried about having enough troops to police his world, the Man of Steel begins to recruit some of Earth''s deadliest villains to his side. Does the Dark Knight have any chance of ending the Man of Steel''s rule? The finale is here, as writer Brian Buccellato (THE FLASH) unveils the final chapter before the events of the hit video game phenomenon in INJUSTICE: GODS AMONG US YEAR FIVE VOL. 2. Collects issues #7-12.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4.5,"review":"","added":9999361,"hdCover":""},{"id":"0989400","title":"Injustice: Gods Among Us: Year Five, Vol. 1","author":"Брайан Буччеллато","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003548163/140/b1ab/Brajan_Buchchellato__Injustice_Gods_Among_Us_Year_Five_Vol._1.jpg","isbn":"1401267688","publisher":"DC Comics","pubDate":"2016","language":"","series":"Injustice","genres":[],"annotation":"This is it: the final year of INJUSTICE: GODS AMONG US, leading into the storyline of the hit videogame! Having defeated the Green Lantern Corps, the forces of magic, and now the gods themselves, the Superman''s totalitarian regime seems to have eliminated all threats. Yet uneasy lies the crown on the head of the Man of Steel. Still obsessed with the outlaw Batman and worried about having enough troops to police his world, The Man of Steel begins to recruit some of Earth''s deadliest villains to his side. Does the Dark Knight have any chance of ending the Man of Steel''s rule? The beginning of the end is here, as writer Brian Buccellato (THE FLASH) unveils the final chapter before the events of the hit video game phenomenon in INJUSTICE: GODS AMONG US YEAR FIVE VOL. 1. Collects issues #1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4,"review":"","added":9999360,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893ff","title":"Injustice: Gods Among Us: Year Four, Vol. 2","author":"Брайан Буччеллато","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003533196/140/a5d5/Brajan_Buchchellato__Injustice_Gods_Among_Us_Year_Four_Vol._2.jpg","isbn":"1401262686","publisher":"DC Comics","pubDate":"2016","language":"","series":"Injustice","genres":[],"annotation":"The shattering conclusion to the Year of the Gods! In this final volume of Year Four, the balance of power may be tipped by the arrival of a force that could challenge even the Gods of Olympus. Also, Wonder Woman must make a stand, and the final fate of Ares is revealed.  The newest chapter of the INJUSTICE saga is here, as writer Brian Buccellato further explores that take place before the events of the hit video game phenomenon. Collects INJUSTICE GODS AMONG US YEAR FOUR #6-12.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":3.5,"review":"","added":9999359,"hdCover":""},{"id":"09893fe","title":"Injustice: Gods Among Us Year Four Vol. 1","author":"Брайан Буччеллато","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001900694/140/06e2/Brajan_Buchchellato__Injustice_Gods_Among_Us_Year_Four_Vol._1.jpg","isbn":"1-401-26130-2","publisher":"","pubDate":"2016","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":3.5,"review":"","added":9999358,"hdCover":""},{"id":"09893fd","title":"Injustice. Боги среди нас. Год третий. Книга 2","author":"Брайан Буччеллато","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003031968/140/efe9/Brajan_Buchchellato__Injustice._Bogi_sredi_nas._God_tretij._Kniga_2.jpg","isbn":"978-5-389-14750-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Каждая из сторон конфликта между Суперменом и Бэтменом призвала себе на помощь потусторонние силы. Но когда противники осознают, насколько эти силы не поддаются контролю, становится уже слишком поздно. И выбрать меньшее из двух зол уже нельзя. Единственный способ предотвратить очередной глобальный кризис — объединиться, чтобы остановить новую беду...  Неожиданный поворот событий вынудил враждующие стороны привлечь в свои ряды таких союзников как Джон Константин, Доктор Фатум, Болотная Тварь. Цель обоих противостоящих групп – не дать надвигающемуся хаосу поглотить все сущее. Ибо война идет уже не только за Землю, но за саму реальность!  Откройте мир, где события культовой видеоигры от создателей MORTAL KOMBAT получают продолжение в книге INJUSTICE: БОГИ СРЕДИ НАС. ГОД ТРЕТИЙ. Новый автор Брайан Буччеллато (ФЛЭШ), художники Бруно Редондо (ЖИВАЯ МИШЕНЬ) и Майк С. Миллер (БЭТМЕН: НЕУКРОТИМЫЙ АРКХЕМ) представляют очередную серию головокружительных сюжетных поворотов в перевернутой с ног на голову вселенной DC! В книгу «INJUSTICE: БОГИ СРЕДИ НАС. ГОД ТРЕТИЙ. КНИГА 2» вошли выпуски с 8-го по 12-й и первый ежегодный выпуск.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4.5,"review":"","added":9999357,"hdCover":""},{"id":"09893fc","title":"Injustice. Боги среди нас. Год третий. Книга 1","author":"Том Тейлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002841192/140/4b0a/Tom_Tejlor__Injustice._Bogi_sredi_nas._God_tretij._Kniga_1.jpg","isbn":"978-5-389-14544-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Линия фронта разделила героев на два враждующих лагеря. По одну сторону – Супермен c Лигой Справедливости и Корпусом Синестро, По другую — армия Бэтмена и Корпус Зеленых Фонарей. И теперь Супермен носит желтое кольцо, питающееся страхом, и на его руках – кровь Черной Канарейки, которую он убил на глазах всего мира. Но Бэтмен не сдается — и у него всегда есть запасной план.  В мире осталась лишь одна сила, способная повергнуть криптонца, — магия. И Джон Константин — оккультист, детектив и мошенник, у которого собственный счет к Супермену, — пополняет армию Бэтмена могущественными чародеями. Теперь, когда союзниками Бэтмена становятся самые сильные колдуны, у Супермена практически не остается шансов на победу.  И все же... Некая таинственная сила защищает Супермена и стремится защитить установленный им мировой порядок. И она способна уничтожить сильнейших – и даже вечных – героев Вселенной.  Откройте для себя мир культовой видеоигры в книге «INJUSTICE: БОГИ СРЕДИ НАС. ГОД ТРЕТИЙ»! Невероятные и обескураживающие повороты сюжета от блестящего сценариста Тома Тэйлора («ЗЕМЛЯ 2») и художников Бруно Редондо (ЖИВАЯ МИШЕНЬ») и Майка С. Миллера («БЭТМЕН: НЕУКРОТИМЫЙ АРКХЕМ») заставят вас по-новому взглянуть на преображение Вселенной DC! В книгу вошли выпуски с первого по седьмой.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4,"review":"","added":9999356,"hdCover":""},{"id":"09893fb","title":"Планета Халка","author":"Грэк Пак","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002896647/140/83b4/Grek_Pak__Planeta_Halka.jpg","isbn":"978-5-91878-282-8","publisher":"Фантастика Книжный Клуб","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Преданный героями Земли и изгнанный в открытый космос, человек-чудовище Халк приземлился на далёкой планете Сакаар, которой правит тиран Красный король. Проданный в рабство, Халк становится Зелёным Шрамом, самым могучим гладиатором на планете. Но его новые хозяева не знают, на что он в действительности способен. Халк создаёт братство с товарищами по арене: хитроумным Миком, ужасной Рой, мудрым каменным человеком Коргом, воином-тенью Хироимом, благородной бунтаркой Эллои и её верным телохранителем Ски. Вместе эти гладиаторы разжигают революцию, которая должна изменить весь мир — или уничтожить его. Суровое научное фэнтези от отмеченного наградами автора Грега Пака, в гостевой роли — Серебряный Сёрфер!  В издание входят «Невероятный Халк» № 92–105, «Планета Халка: Путеводитель по гладиаторским боям» и материалы из Amazing Fantasy № 15 и «Гигантского Халка» № 1.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4,"review":"","added":9999355,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893fa","title":"Капитан Америка жив!","author":"Эд Брубейкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003160434/140/29a1/Ed_Brubejker__Kapitan_Amerika_zhiv.jpg","isbn":"978-5-91878-333-7","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Только люди стали привыкать к Баки Барнсу в образе нового патриотического символа со знаменитым щитом, только он начал внушать легендарным врагам Кэпа не меньший страх, чем покойный Стив Роджерс… Как злодей из прошлого вернулся, чтобы отравить Баки его настоящее. Чудовищная интрига закручивается, а в эпицентре — Шэрон Картер, до сих пор живущая во власти воспоминаний о том, какую роль она сыграла в день смерти своего возлюбленного, Стива. Теперь её одержимость обострили ночные кошмары — видения, сквозь которые пытается пробиться невероятная истина: Стив Роджерс жив. И она, Шерон, может спасти его. Как поступят друзья и враги Капитана Америка, узнав её секрет, и долго ли она проживёт на пути к Возрождённому? Эпохальный сюжет, на создание которого ушло пять лет, — «Возрождённый» Эда Брубейкера и Брайана Хитча — наконец перед нами. Захватывающая история, где мы обнаруживаем, что пусть мечта и не умерла окончательно, но она поглощена абсолютным злом. Судьба Роджерса — в руках Красного Черепа и его гнусных приспешников, и только Шэрон, Баки, Сокол и другие Мстители могут спасти Стива от участи худшей, чем небытие. Дополнительно: в истории, удостоенной премии Айснера за «Лучший отдельный выпуск», прославленный художник Джин Колан вновь вводит одного из персонажей, которого создал когда-то, повествуя о событиях времён Второй мировой.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4,"review":"","added":9999354,"hdCover":""},{"id":"09893f9","title":"Чудо-Женщина. Книга 1. Кровь и смерть","author":"Брайан Аззарелло","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002275818/140/158e/Brajan_Azzarello__ChudoZhenschina._Kniga_1._Krov_i_smert.jpg","isbn":"978-5-389-12452-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Дочь царицы амазонок, принцесса-воительница Диана не похожа на своих соплеменниц. Согласно легенде бездетная царица Ипполита вылепила себе дочку из глины, и амазонки смотрят на Диану, как на изгоя, хотя во внешнем мире она – супергероиня, которая сражается за справедливость.  А тем временем олимпийские боги играют в свои темные игры. Блудный сын Аполлон метит на освободившийся трон Зевса, и пламя конфликта опалит как мстительных богов, так и ни в чем не повинных смертных.  И кто же в центре разгорающегося пожара? Чудо-Женщина и тайна, которой суждено разрушить весь ее привычный мир. Чудо-Женщина вот-вот узнает правду о своем происхождении. И тогда прольется кровь…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4,"review":"","added":9999353,"hdCover":""},{"id":"09893f8","title":"Тор. Том 2","author":"Джей Майкл Стражински","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004119771/140/3247/Dzhej_Majkl_Strazhinski__Tor._Tom_2.jpg","isbn":"978-5-91878-351-1","publisher":"Фантастика","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После Рагнарёка, пробудившись от сна богов, Тор решил восстановить былое величие Асгарда — сделать его ещё более величественным и великолепным, чем прежде. Он возродил бесчисленное множество сородичей — скандинавских богов, от храброго Бальдра до огромного Вольштагга и хитрого Локи. Но что же Один Всеотец? Где лев северных легенд, сын Бора, тот, кто взял шайку буйных воинственных богов и превратил её в пантеон, не знающий себе равных? Почему он всё ещё не проснулся? Это секрет, известный лишь Богу Грома, спрятанный в глубине души, исполненной страхом и унижением, которые может испытывать только сын в необъятной тени отца. Но, как вскоре покажет хитрый план Локи, не у одного Тора есть секреты. Включает выпуски «Тора» № 10–12, 600–603 и гигантский финальный выпуск от сценариста Дж. Майкла Стражински («Вавилон-5» и «Удивительный Человек-Паук») и художника Оливье Койпела («Мстители»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4.5,"review":"","added":9999352,"hdCover":""},{"id":"09893f7","title":"Тор. Том 1","author":"Джей Майкл Стражински","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003847792/140/e6df/Dzhej_Majkl_Strazhinski__Tor._Tom_1.jpg","isbn":"978-5-91878-415-0","publisher":"Фантастика","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Асгардский бог грома вернулся в пантеон великих героев Marvel и воссоединился со своей смертной оболочкой — доктором Доном Блейком. Вместе им предстоит столк- нуться с наследием мифического королевства севера и пробуждением его бессмертных героев — в мире, который может оказаться не рад их возвращению! Включает выпуски «Тора» № 1–9 от сценариста Дж. Майкла Стражински («Вавилон-5» и «Удивительный Человек-Паук») и художника Оливье Койпела («Мстители»).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":4.5,"review":"","added":9999351,"hdCover":""},{"id":"09893f6","title":"Бэтмен. Готэм Нуар","author":"Эд Брубейкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003089673/140/e883/Ed_Brubejker__Betmen._Gotem_Nuar.jpg","isbn":"978-5-389-16773-5","publisher":"Азбука","pubDate":"2019","language":"Русский","series":"Графические романы. Бэтмен","genres":["Комиксы","манга","графические романы"],"annotation":"Готэм-сити погружается в нуар! В этом необычном ваншоте Эд Брубейкер, автор, подаривший миру историю о первой встрече Бэтмена и Джокера в комиксе «Человек, который смеется», помещает всем известных героев в атмосферу безысходных 50-х, наполненную гангстерами в широких шляпах, роковыми женщинами и мрачными тайнами. Такого Темного Рыцаря и его родной город вы еще никогда не видели!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999350,"hdCover":""},{"id":"09893f5","title":"Смерть Капитана Америка","author":"Джексон Гайс,Эд Брубейкер,Стив Эптинг,Майк Перкинс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002992574/140/b43f/__Smert_Kapitana_Amerika.jpg","isbn":"978-5-91878-327-6","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"Серия","genres":["Комиксы","манга","графические романы"],"annotation":"Он был кумиром миллионов, примером для подражания всех вооружённых сил Америки и воплощением главных ценностей своего народа. Он жил ради своей страны — и сейчас, застреленный хладнокровным убийцей, до конца, без остатка отдал себя любимой отчизне. Отомстить за смерть Кэпа — вот что стало теперь главной задачей его старого напарника Сокола. Шэрон Картер всё больше теряет власть над собой, превращаясь в марионетку прихвостней Красного Черепа. А Баки Барнс, Зимний Солдат, должен найти способ примирить своё позорное прошлое с призывом стать новым Капитаном Америка!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999349,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893f4","title":"Вселенная DC. Rebirth. Бэтмен. Detective Comics. Книга 6. Бэтмены навсегда (сборник)","author":"Джеймс Тайнион IV","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003626886/140/07ea/Dzhejms_Tajnion_IV__Vselennaya_DC._Rebirth._Betmen._Detective_Comics._Kniga_6._B.jpg","isbn":"978-5-38-917155-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Рыцари Готэма – вместе навсегда!  Тим Дрейк остался жив и вновь стоит на страже порядка. Вместе с Рыцарями Готэма он помогает Бэтмену бороться с преступностью в городе. Однако Синдикат Жертв не оставляет борцов за справедливость в покое, он хочет одного: расквитаться с Бэтменом и разрушить все, что тот успел создать. Преступники похищают Глиноликого и угрожают выпустить на свободу самых опасных пациентов Аркхема, если Темный Рыцарь не снимет маску в прямом эфире. И это лишь начало конца…  Бэтвумен, оказавшись перед сложным выбором, поступается с принципами Бэтмена и покидает команду. За ней уходят еще двое членов бэт-семейства. Случившимся незамедлительно пользуется Колония, переманивая изгоев на свою сторону. На фоне всего этого зловещая кибернетическая сущность пытается преобразовать Красного Робина в универсальное оружие и тем самым обречь Готэм на худший из вариантов будущего.  Чтобы воссоединить команду и спасти свой город, Бэтмену необходимо довериться каждому, кто носит на груди символ летучей мыши. Ведь со щитом или на щите – они должны быть вместе.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999348,"hdCover":""},{"id":"09893f3","title":"Вселенная DC. Rebirth. Бэтмен. Detective Comics. Книга 5. Одинокое место для жизни (сборник)","author":"Джеймс Тайнион IV,Эдди Барроуз","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003054606/140/c644/__Vselennaya_DC._Rebirth._Betmen._Detective_Comics._Kniga_5._Odinokoe_mesto_dlya.jpg","isbn":"978-5-389-16726-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Тим Дрейк возвращается… И сама смерть следует за ним!  Долгие месяцы Бэтмен страдал из-за смерти Тима Дрейка, юного героя, который сражался на его стороне в образе Красного Робина. Тим помог Бэтмену собрать команду героев и изгоев для защиты Готэма, а сам погиб, спасая город. По крайней мере, все были в этом уверены…  Но на самом деле за мгновение до смерти Тим перенесся в неизвестное место, где встретился с незнакомцем в капюшоне, который называл себя мистер Оз. Робин оказался в заключении в тюрьме вне времени, и все его попытки сбежать оттуда так и не увенчались успехом. Но однажды Оз покидает свои угодья, и Тиму Дрейку выпадает единственный шанс спастись. Вернуться в родной город ему помогает загадочный пленник. Однако Робин еще не подозревает, какую опасность он представляет для Готэма и всей бэт-семьи …  Джеймс Тайнион IV, Эдди Барроуз, Альваро Мартинес и Кармен Карнеро продолжают свой ран на серии «Detective Comics», лихо закручивая сюжет и удивляя читателей непредсказуемыми поворотами. В книгу вошли выпуски #963–968.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999347,"hdCover":""},{"id":"09893f2","title":"Вселенная DC. Rebirth. Бэтмен. Detective Comics. Книга 4. Бог из машины (сборник)","author":"Джеймс Тайнион IV","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003016053/140/bd76/Dzhejms_Tajnion_IV__Vselennaya_DC._Rebirth._Betmen._Detective_Comics._Kniga_4._B.jpg","isbn":"978-5-389-14364-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Знание – сила… Сила – это власть, а власть развращает!  Впервые за долгое время в жизни бэт-семьи все спокойно: Кейт, Люк и Жан-Поль отправляются на баскетбольный матч, Касандра и Глиноликий оттачивают актерское мастерство, а Брюс Уэйн находит способ получить ответы на давно интересующие его вопросы. Но зло не заставляет себя ждать…  Кто-то начинает уничтожать членов ордена святого Дюма, и Жан-Поль понимает, что это дело рук нового Азраила. Только в этот раз Ангелом Смерти оказывается не человек из плоти и крови, а нечто совсем иное...  Что поможет героям остановить очередного Азраила? Какая сила способна противостоять машине для убийств, не ведающей страха? Быть может… магия?  Джеймс Тайнион IV и Альваро Мартинес открывают очередную главу масштабной истории готэмских рыцарей. Специальная гостья сборника – волшебница Затанна! В книгу вошли выпуски #957–962.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999346,"hdCover":""},{"id":"09893f1","title":"Человек-Паук. Новый день. Том 3","author":"Дэн Слотт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003962016/140/917a/Den_Slott__ChelovekPauk._Novyj_den._Tom_3.jpg","isbn":"978-5-04-109455-3","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Человек-Паук. Избранное","genres":["Комиксы","манга","графические романы"],"annotation":"В результате землетрясения Паучок оказался заперт под землёй вместе с целым составом метро, полным жителей Нью-Йорка. Но как к этому причастны серьёзный криминальный босс, текущий судебный процесс и… Джей Джона Джеймсон? Когда странный безликий преступник подвергает жизнь тёти Мэй опасности, Человек-Паук бросается его остановить. Но как это сделать, если враг способен выскользнуть из твоей паутины? Вы увидите, как Гарри Озборн вернулся к жизни и кто терроризировал людей в образе Угрозы! Познакомитесь с новым мэром Нью-Йорка! Узнаете, как сильно приключения прошлого влияют на будущее Человека-Паука и Фантастической Четвёрки! Задрожите при виде зловещего Лешего! А также дополнительная история: Человек-Паук объединяется с президентом Обамой!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999345,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893f0","title":"Бэтмен Проклятый","author":"Брайан Азарелло,Ли Бермехо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003929727/140/e8ad/__Betmen_Proklyatyj.jpg","isbn":"978-5-389-17730-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Джокер мертв.  Сомнений нет. Но кто виновен в его смерти? Бэтмен пытается найти ответ на этот вопрос, но что-то постоянно мешает ему: какая-то мелкая деталь ускользает от величайшего в мире детектива, и он все больше убеждается, что в этом деле замешаны сверхъестественные силы.  А кто лучше других способен раскрывать оккультные заговоры? Конечно же, эксцентричный британский маг — Джон Константин.  Есть лишь маленькая проблемка: пусть Джон и любит разгадывать загадки, ничуть не меньше ему нравится влезать людям в головы. С таким помощником Бэтмену предстоит посетить жуткую изнанку Готэма, чтобы выяснить неожиданную правду о том, кто же на самом деле убил его заклятого врага.  Издание включает выпуски мини-серии «БЭТМЕН ПРОКЛЯТЫЙ» №1–3, а также содержит дополнительные материалы от Ли Бермехо и послесловие от Брайана Аззарелло.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999344,"hdCover":""},{"id":"09893ef","title":"Люди Икс. Великий замысел #2","author":"Эдвард Пискор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002951224/140/46bc/Edvard_Piskor__Lyudi_Iks._Velikij_zamysel_2_.jpg","isbn":"978-5-6041374-6-8","publisher":"Белое Яблоко","pubDate":"2018","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"На протяжении более шести взбалмошных десятилетий \"Люди Икс\" отстаивали свое исключительное место во вселенной комиксов и популярной культуры. С момента их яркого рождения в шестидесятых, через знаменательный перезапуск в семидесятых, до поиска себя в девяностых и битвы против забвения в нулевых \"Люди Икс\" затронули не одно поколение читателей. Всё это время вселенная \"Людей Икс\" постоянно видоизменялась и разрасталась. Эд Пискор, автор \"Родословной хип-хопа\", взял на себя смелость пересказать историю вселенной \"Людей Икс\", в результате чего получился масштабный труд, в котором воедино сошлись классические и забытые истории, рассказывающие об эволюции этой вселенной. Во втором номере \"Людей икс. Великий замысел\" впервые возникают Стражи, открывают Дикую Землю, кое-что про Чарльза Ксавье и не только. В этом номере количество задействованных персонажей вырастает в геометрической прогрессии. События принимают крутой оборот. Но, как говорит один из персонажей - \"пока вселенная жива и крутится, история не будет рассказана до конца\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999343,"hdCover":""},{"id":"09893ee","title":"Люди-Икс. Великий замысел . Выпуск №1","author":"Пискор Э.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002891866/140/edf4/Piskor_E.__LyudiIks._Velikij_zamysel_._Vypusk_No1.jpg","isbn":"978-5-6041374-2-0","publisher":"Белое Яблоко","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"На протяжении более шести взбалмошных десятилетий \"Люди Икс\" отстаивали свое исключительное место во вселенной комиксов и популярной культуры. С момента их яркого рождения в шестидесятых, через знаменательный перезапуск в семидесятых, до поиска себя в девяностых и битвы против забвения в нулевых \"Люди Икс\" затронули не одно поколение читателей. Всё это время вселенная \"Людей Икс\" постоянно видоизменялась и разрасталась. Эд Пискор, автор \"Родословной хип-хопа\", взял на себя смелость пересказать историю вселенной \"Людей Икс\", в результате чего получился масштабный труд, в котором воедино сошлись классические и забытые истории, рассказывающие об эволюции этой вселенной. Первый номер серии \"Люди Икс: Великий Замысел\" Эда Пискора повествует о самом начале зарождения этой вселенной. О том, как Чарльз Ксавье собрал вокруг себя Циклопа, Джину Грей, Человека-льда, Архангела и Зверя. Этот выпуск обязателен к прочтению всем фанатам, которые хотят разобраться в хитросплетениях вселенной Людей Икс!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999342,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893ed","title":"Лига Справедливости. Книга 7. Война Дарксайда. Часть 2","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002753965/140/a918/Dzheff_Dzhons__Liga_Spravedlivosti._Kniga_7._Vojna_Darksajda._Chast_2.jpg","isbn":"978-5-389-13773-8","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"После смерти Дарксайда мир перевернулся: Супермен, Бэтмен, Флэш, Зеленый Фонарь, Шазам и Лекс Лютор становятся Новыми Богами. Теперь они практически всемогущи! А это нелегкое испытание даже для супергероев. С каждой минутой в них остается все меньше человеческого – такова цена обретенной власти. Киборг и Кольцо Силы тоже больше не принадлежат сами себе. Лишь Диана, принцесса амазонок, не изменяет своим принципам, продолжая защищать человечество от зла. Тем временем Грааль постигла Уравнение Анти-Жизни и хочет с его помощью уничтожить Лигу Справедливости, а Анти-Монитор вознамерился стереть в порошок все на своем пути. Чтобы остановить войну, супергерои вынуждены обратиться за помощью к своим заклятым врагам – Преступному Синдикату! Но какова цена этого союза? Ведь за все в этой жизни надо платить…  Суперзвезда мира комиксов Джефф Джонс подводит заключительную черту под эпопеей, продолжавшейся четыре года. Величайшие герои во вселенной, созданные Джонсом в соавторстве с известными художниками Джейсоном Фейбоком и Фрэнсисом Манапулом, завершают грандиозную Войну Дарксайда. Книга включает выпуски № 45–50 и специальный выпуск № 1 «Лига Справедливости. Война Дарксайда».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":5,"review":"","added":9999341,"hdCover":""},{"id":"09893ec","title":"Siege: Embedded","author":"Крис Сэмни,Брайан Рид","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003224519/140/f471/__Siege_Embedded.jpg","isbn":"9780785147640","publisher":"Marvel","pubDate":"2010","language":"Английский","series":"","genres":[],"annotation":"The SIEGE of Asgard has begun And Norman Osborn and his Dark Avengers are leading the charge Osborn''s savvy use of the media fueled his rise to power - but the very tools he''s been using may turn against him. It''s time to expose Norman''s true face to the world and uncover the secrets behind the attack on the gods Witness the changing of the Marvel Universe firsthand Collects Siege: Embedded #1-4 and Fallen.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":2.5,"review":"","added":9999340,"hdCover":""},{"id":"09893eb","title":"Siege: Avengers: The Initiative","author":"Кристос Гейдж,Рафа Сандовал","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003212154/140/ff0d/__Siege_Avengers_The_Initiative.jpg","isbn":"978-0785148180","publisher":"Marvel","pubDate":"2010","language":"Английский","series":"","genres":[],"annotation":"Months of story threads fi nally weave together as Norman Osborn offers Taskmaster a seat at the Cabal''s table...the Avengers Resistance uncovers a horrifying secret...and members of the Initiative are called up for an assault on an enemy of incalculable power!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999339,"hdCover":""},{"id":"09893ea","title":"Siege: X-Men","author":"Дэниел Уэй","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003224503/140/1579/Deniel_Uej__Siege_XMen.jpg","isbn":"9780785148159","publisher":"Marvel","pubDate":"2010","language":"Английский","series":"","genres":[],"annotation":"The end has come. While he is counted among the greatest villains the Marvel Universe has ever seen, one question remains: whose side is Daken really on? As part of the Siege on Asgard, what, or who, will he encounter in the land of the gods that will change him forever? And in New Mutants, with all the Asgardians falling in the Siege of Asgard, someone needs to deal with the dead. And who better to do so than a Valkyrie. But where is Dani Moonstar supposed to be bringing these dead?  Collecting: Dark Wolverine 82-84, New Mutants 11, Siege: Storming Asgard Heroes & Villains","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3,"review":"","added":9999338,"hdCover":""},{"id":"09893e9","title":"Fantastic Four: The Life Fantastic","author":"Джей Майкл Стражински,Карл Кесел","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003192139/140/1969/__Fantastic_Four_The_Life_Fantastic.jpg","isbn":"978-0785118961","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":[],"annotation":"FOUR FANTASTIC TALES OF THE FF! - When a doomsday weapon manufactured by Hydra turns up in the Nevada desert, there''s only one man the authorities can ask to go in and defuse it: Bruce Banner! What does all of this have to do with the FF, you ask? Well, who do you think has to deal with the fallout when it all goes terribly wrong? - It''s hard to believe Reed and Sue tied the knot 40 years ago... and it certainly doesn''t seem that much time has passed to Reed and Sue themselves when a special evening out gives them a chance to look over their entire life together- past, present and future! - The Invisible Woman is dead! As Reed cradles his murdered wife, lost in grief, and Ben rampages after Sue''s killer, Johnny defiantly decides to do whatever it takes- no matter the cost or consequence- to see his sister alive again. What he does will change the way the Fantastic Four look at him forever. - It''s a day of celebration and reflection in Latveria, but deep within the confines of the Latverain Embassy to America, Victor Von Doom and Reed Richards engage in a subtle battle of wits, with all of Manhattan as the playing field. What are the stakes? And can Mister Fantastic triumph when all the moves have been made in advance?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999337,"hdCover":""},{"id":"09893e8","title":"Siege: Thunderbolts","author":"Jeff Parker","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002122922/140/15b0/Jeff_Parker__Siege_Thunderbolts.jpg","isbn":"978-0785143734","publisher":"Marvel","pubDate":"2010","language":"Английский","series":"","genres":[],"annotation":"It''s been too long since Mr. X has killed, and he needs his next fix! Ghost has taken notice, and sees an opportunity...while Scourge is seeing things that no one should! Add in the selfish intentions of Paladin and Ant-Man, stir with a stick of dynamite and...BOOM! You''ve heard raves about Parker''s ATLAS (heroes pretending to be villains)...but now it''s time to let him loose on some real fiends!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3,"review":"","added":9999336,"hdCover":""},{"id":"09893e7","title":"Thor: Siege","author":"Kieron Gillen","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848205/140/4d8e/Kieron_Gillen__Thor_Siege.jpg","isbn":"9780785148142","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Asgard lies under SIEGE! As the evil eye of Norman Osborn falls on Asgard, what happens to neighboring Broxton, Oklahoma? What unexpected enemies will be drawn to the scene like carrion to a carcass? And what unlikely heroes will rise to the town''s defense? The Asgardians face the battle of their lives...and the showdown that''s coming may end their new life on Earth as quickly as it began! Then, delve into the world of Siege''s most devious major player in SIEGE: LOKI!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999335,"hdCover":""},{"id":"09893e6","title":"Dark Avengers: Siege","author":"Bendis, Brian Michael","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848204/140/6c4c/Bendis_Brian_Michael__Dark_Avengers_Siege.jpg","isbn":"9780785148128","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"After years of mystery, the secrets of the Sentry are revealed! How deep is his madness and who is really in control of him? What is the limit of his power, if any? And what deadly mystery surrounds him causing mortals and gods to tremble in fear? Plus: In the middle of SIEGE, Ms. Marvel and Hawkeye take center stage in a sick twisted battle, and launch their own agenda, revealing their true relationship, and their personal plans for Norman Osborn.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999334,"hdCover":""},{"id":"09893e5","title":"New Avengers: Siege","author":"Bendis, Brian Michael","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848095/140/6de8/Bendis_Brian_Michael__New_Avengers_Siege.jpg","isbn":"9780785145783","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Steve Rogers makes his triumphant return to the Avengers, but is he too late? When the gods fall, what chance does a Super Soldier stand? Also, the ladies of the Avengers ban together to save the team. Plus, Ronin breaks into Avengers Tower to assassinate Osborn! This volume also includes the NEW AVENGERS conclusion by superstar Bryan Hitch.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999333,"hdCover":""}]');
